function solve(nums: number[], queries: number[][]): number[] {
    // Precompute the popcount-depth for each number in nums
    const popcountDepth: number[] = nums.map(num => {
        let current = num;
        let depth = 0;
        while (current > 0) {
            current = popcount(current);
            depth++;
        }
        return depth;
    });

    // Function to compute the popcount of a number
    function popcount(x: number): number {
        return x.toString(2).split('1').length - 1;
    }

    // Build a frequency map for each depth
    const freq: Map<number, number[]> = new Map();
    for (let i = 0; i < nums.length; i++) {
        const depth = popcountDepth[i];
        if (!freq.has(depth)) {
            freq.set(depth, new Array(nums.length).fill(0));
        }
        freq.get(depth)![i] = 1;
    }

    // For each depth, create a prefix sum array for efficient range queries
    const prefixSums: Map<number, number[]> = new Map();
    for (const [depth, arr] of freq.entries()) {
        const prefix = new Array(arr.length + 1).fill(0);
        for (let i = 0; i < arr.length; i++) {
            prefix[i + 1] = prefix[i] + arr[i];
        }
        prefixSums.set(depth, prefix);
    }

    // Process each query
    const answer: number[] = [];
    for (const query of queries) {
        if (query[0] === 1) {
            const [l, r, k] = query.slice(1);
            const prefix = prefixSums.get(k);
            if (prefix) {
                const count = prefix[r + 1] - prefix[l];
                answer.push(count);
            } else {
                answer.push(0);
            }
        } else {
            const [idx, val] = query.slice(1);
            // Update the value in nums
            nums[idx] = val;
            // Recompute the popcount-depth for the updated value
            const newDepth = popcountDepth[idx];
            // Update the frequency map
            const oldDepth = popcountDepth[idx];
            if (oldDepth !== newDepth) {
                // Decrement the old depth's count
                if (freq.has(oldDepth)) {
                    freq.get(oldDepth)![idx] = 0;
                }
                // Increment the new depth's count
                if (!freq.has(newDepth)) {
                    freq.set(newDepth, new Array(nums.length).fill(0));
                }
                freq.get(newDepth)![idx] = 1;
                // Update the prefix sums for the old and new depths
                if (prefixSums.has(oldDepth)) {
                    const oldPrefix = prefixSums.get(oldDepth)!;
                    for (let i = 0; i < oldPrefix.length; i++) {
                        oldPrefix[i] = oldPrefix[i] - (freq.get(oldDepth)![i] ? 1 : 0);
                    }
                }
                if (prefixSums.has(newDepth)) {
                    const newPrefix = prefixSums.get(newDepth)!;
                    for (let i = 0; i < newPrefix.length; i++) {
                        newPrefix[i] = newPrefix[i] + (freq.get(newDepth)![i] ? 1 : 0);
                    }
                }
            }
            // Update the popcount-depth for the updated value
            popcountDepth[idx] = newDepth;
        }
    }

    return answer;
}

